   export const registerTools = (tools: ToolRegistry) => {
     // Register each tool with context
     Object.entries(tools).forEach(([name, tool]) => {
       const registeredTool = {
         ...tool,
         execute: async (toolCallId, params, signal, onUpdate, ctx) => {
           const wrappedExecute = tool.execute.bind(tool);

           return wrappedExecute(
             toolCallId,
             params,
             signal,
             async (updateContent) => {
               // Emit updates during execution
               onUpdate(updateContent);
             },
             ctx
           );
         },
       };

       // Store in registry
